// MOCK: Simulates a Google Sheets 'New Row' trigger
// In production, replace this with the Google Sheets Trigger node
return [
  {
    json: {
      row_number: 42,
      name: "Jane Smith",
      email: "jane.smith@example.com",
      status: "New Lead",
      created_at: new Date().toISOString()
    }
  }
];

// MOCK: Formats the Slack message payload
// In production, replace this with the Slack node
const row = $input.first().json;

return [
  {
    json: {
      channel: "#leads-notifications",
      text: `:new: New row detected in Google Sheets!\n*Name:* ${row.name}\n*Email:* ${row.email}\n*Status:* ${row.status}\n*Time:* ${row.created_at}`
    }
  }
];

// MOCK: Simulates sending the Slack notification
// In production, replace this with the Slack node (Send Message action)
const payload = $input.first().json;

console.log('MOCK Slack send:', JSON.stringify(payload, null, 2));

return [
  {
    json: {
      ok: true,
      channel: payload.channel,
      message_sent: payload.text,
      mock: true,
      timestamp: new Date().toISOString()
    }
  }
];
